```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ClosedPresaleMint {
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;

    address public owner;
    uint256 public price;
    uint256 public totalSupply;
    uint256 public maxSupply;
    mapping(address => bool) public claimedWhitelistStatus;

    event PresaleStarted();
    event PublicSaleStarted();
    event NFTMinted(address indexed sender);
    event PublicNFTMinted(address indexed sender, uint256 amount);

    constructor(uint256 price_, uint256 maxSupply_) {
        require(msg.sender == tx.origin, "Only deployer can initialize");
        owner = msg.sender;
        price = price_;
        maxSupply = maxSupply_;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Presale already started or in progress");
        currentState = State.PRESALE;
        emit PresaleStarted();
    }

    function startPublicSale() public onlyOwner {
        require(currentState == State.PRESALE, "Public sale cannot be started yet");
        currentState = State.PUBLIC;
        emit PublicSaleStarted();
    }

    function mintNFT() public payable {
        require(currentState == State.PRESALE, "Presale is not active");
        require(!claimedWhitelistStatus[msg.sender], "Already claimed whitelist status");
        require(msg.value == price, "Incorrect payment amount");
        require(totalSupply + 1 <= maxSupply, "Exceeds max supply");

        // Checks-Effects-Interactions pattern
        claimedWhitelistStatus[msg.sender] = true;
        totalSupply += 1;
        emit NFTMinted(msg.sender);
    }

    function mintPublicNFT(uint256 amount) public payable {
        require(currentState == State.PUBLIC, "Public sale is not active");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value == price * amount, "Incorrect payment amount");
        require(totalSupply + amount <= maxSupply, "Exceeds max supply");

        // Checks-Effects-Interactions pattern
        totalSupply += amount;
        emit PublicNFTMinted(msg.sender, amount);
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}
